import{_ as e,o as a,c as i,a5 as s}from"./chunks/framework.COADHF96.js";const g=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md","lastUpdated":1781779105000}'),o={name:"guide/introduction.md"};function n(r,t,l,d,c,h){return a(),i("div",null,[...t[0]||(t[0]=[s(`<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p><strong>Picsart AI Playground</strong> is a prompt interface that wraps every AI model Picsart supports — image, video, and audio — behind one consistent surface. Instead of signing up for a dozen providers, juggling API keys, and learning each one&#39;s quirks, you use a single account and one credit balance.</p><p>There are three ways to use it from outside the web app:</p><table tabindex="0"><thead><tr><th>Interface</th><th>Best for</th><th>Page</th></tr></thead><tbody><tr><td><strong>gen-ai CLI</strong></td><td>Creators and developers working in the terminal; scripting and automation</td><td><a href="/picsart-mcp-cli-docs/guide/cli-quickstart">CLI Quickstart</a></td></tr><tr><td><strong>Skills</strong></td><td>Driving generation in plain English inside Claude Code, Cursor, Windsurf, or ChatGPT</td><td><a href="/picsart-mcp-cli-docs/guide/skills">Skills</a></td></tr><tr><td><strong>MCP</strong></td><td>Any MCP-compatible agent calling the catalog as tools</td><td><a href="/picsart-mcp-cli-docs/guide/mcp-quickstart">MCP Quickstart</a></td></tr></tbody></table><p>All three are powered by the same <code>@picsart/ai-sdk</code> model registry, so the model catalog, parameters, and pricing are identical across them. Skills and MCP drive the CLI under the hood — install it and run <code>gen-ai login</code> once, and every surface works.</p><h2 id="what-you-can-generate" tabindex="-1">What you can generate <a class="header-anchor" href="#what-you-can-generate" aria-label="Permalink to &quot;What you can generate&quot;">​</a></h2><ul><li><strong>Image</strong> — text-to-image, image editing, inpainting, style transfer, background removal/replacement, upscaling, and vector/SVG output. <strong>65 models.</strong></li><li><strong>Video</strong> — text-to-video, image-to-video, video-to-video editing, and clip extension. <strong>58 models.</strong></li><li><strong>Audio</strong> — text-to-speech, music, sound effects, voice design, dubbing, and speech-to-speech. <strong>18 models.</strong></li></ul><p>Browse the full catalog in the <strong><a href="/picsart-mcp-cli-docs/reference/">Model Reference</a></strong>, or filter live:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gen-ai</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                     # full catalog</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gen-ai</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --mode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> video</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # only video models</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gen-ai</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --provider</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> google</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # only Google models</span></span></code></pre></div><h2 id="how-a-generation-works" tabindex="-1">How a generation works <a class="header-anchor" href="#how-a-generation-works" aria-label="Permalink to &quot;How a generation works&quot;">​</a></h2><p>Whether you call it from the CLI or via MCP, every generation follows the same path:</p><ol><li><strong>Pick a model</strong> — by id (e.g. <code>flux-2-pro</code>, <code>seedance-2.0</code>) or let the CLI/agent help you choose.</li><li><strong>Provide inputs</strong> — a prompt, plus optional images/videos/audio and model parameters (aspect ratio, duration, resolution…).</li><li><strong>(Optional) quote the cost</strong> — every model exposes its credit cost before you spend anything.</li><li><strong>Generate</strong> — the request is submitted, polled to completion, and the result URL is returned (and optionally downloaded or saved to your Picsart Drive).</li></ol><p>The model never talks to vendor APIs directly — all generation flows through the Picsart platform, which is why one account and one credit balance cover everything.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><strong><a href="/picsart-mcp-cli-docs/guide/installation">Installation</a></strong> — install the CLI and connect the MCP server.</li><li><strong><a href="/picsart-mcp-cli-docs/guide/authentication">Authentication</a></strong> — log in once.</li><li><strong><a href="/picsart-mcp-cli-docs/guide/cli-quickstart">CLI Quickstart</a></strong> · <strong><a href="/picsart-mcp-cli-docs/guide/mcp-quickstart">MCP Quickstart</a></strong></li></ul>`,15)])])}const u=e(o,[["render",n]]);export{g as __pageData,u as default};
